SET NAMES utf8mb4;

CREATE TABLE `inventory_value_calc_details`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'СИ╗сѓГсЃ╝',
  `run_id` int NOT NULL COMMENT 'Уеѕу«ЌсЃљсЃЃсЃЂID',
  `inventory_log_id` int NULL DEFAULT NULL COMMENT 'ТБџтЇИсЃГсѓ░ID',
  `product_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL,
  `process_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL,
  `item_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT 'тї║тѕє (ТЮљТќЎ/жЃетЊЂ/сѓ╣сЃєсЃ╝)',
  `quantity` decimal(12, 4) NULL DEFAULT 0.0000,
  `route_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT 'жЂЕућесЃФсЃ╝сЃѕCD',
  `step_no` int NULL DEFAULT NULL COMMENT 'жЂЕућесѓ╣сЃєсЃЃсЃЌ',
  `unit_price_snapshot` decimal(18, 6) NULL DEFAULT NULL COMMENT 'сѓ╣сЃісЃЃсЃЌсѓисЃДсЃЃсЃѕу┤»УеѕтЇўСЙА',
  `amount` decimal(18, 2) NULL DEFAULT NULL COMMENT 'жЄЉжАЇ (ТЋ░жЄЈ├ЌтЇўСЙА)',
  `price_rule_id` int NULL DEFAULT NULL COMMENT 'жЂЕућетЇўСЙАсЃФсЃ╝сЃФID',
  `error_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT 'сѓесЃЕсЃ╝сѓ│сЃ╝сЃЅ (NULL=ТГБтИИ)',
  `error_message` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NULL DEFAULT NULL COMMENT 'сѓесЃЕсЃ╝тєЁт«╣',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_calc_detail_run`(`run_id` ASC) USING BTREE,
  INDEX `idx_calc_detail_product`(`product_cd` ASC, `process_cd` ASC) USING BTREE,
  CONSTRAINT `fk_calc_detail_run` FOREIGN KEY (`run_id`) REFERENCES `inventory_value_calc_runs` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 733 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_bin COMMENT = 'ТБџтЇИжЄЉжАЇУеѕу«ЌТўју┤░' ROW_FORMAT = Dynamic;
